import React, { useState, useEffect } from "react";
import axios from "axios";
import { motion, AnimatePresence } from "framer-motion";

const AdvisoryForm = () => {
  const [user, setUser] = useState("");
  const [advisory, setAdvisory] = useState("");
  const [advisories, setAdvisories] = useState([]);
  const [showAll, setShowAll] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  useEffect(() => {
    fetchAdvisories();
  }, []);

  const fetchAdvisories = async () => {
    setLoading(true);
    try {
      const response = await axios.get("http://localhost:5000/api/advisory/getAll");
      setAdvisories(response.data);
    } catch (err) {
      setError("Failed to fetch advisories.");
    } finally {
      setLoading(false);
    }
  };

  const submitAdvisory = async () => {
    if (!user || !advisory) {
      setError("Please enter both name and advisory.");
      return;
    }
    setLoading(true);
    setError("");

    try {
      const newAdvisory = { user, advisory };
      await axios.post("http://localhost:5000/api/advisory/add", newAdvisory);

      // Smooth animation when adding advisory
      setAdvisories((prev) => [{ ...newAdvisory, id: Date.now() }, ...prev]);
      setUser("");
      setAdvisory("");
    } catch (err) {
      setError("Failed to submit advisory.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ backgroundColor: "#F5DEB3", minHeight: "100vh", padding: "20px" }}>
      <div style={{ maxWidth: "900px", margin: "auto", padding: "15px" }}>
        <motion.div
          initial={{ opacity: 0, y: -30 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5 }}
          style={{
            padding: "20px",
            border: "1px solid #8B4513",
            borderRadius: "10px",
            backgroundColor: "#FAF3E0",
            boxShadow: "0px 4px 6px rgba(0, 0, 0, 0.1)",
          }}
        >
          <h2 style={{ color: "#121111", textAlign: "center" }}>Advisory Section</h2>

          <div style={{ marginBottom: "20px" }}>
            <motion.input
              type="text"
              placeholder="Your Name"
              value={user}
              onChange={(e) => setUser(e.target.value)}
              whileFocus={{ scale: 1.05 }}
              transition={{ duration: 0.3 }}
              style={{
                padding: "8px",
                width: "100%",
                marginBottom: "10px",
                border: "1px solid #8B4513",
                borderRadius: "5px",
              }}
            />
            <motion.textarea
              placeholder="Write your advisory here..."
              value={advisory}
              onChange={(e) => setAdvisory(e.target.value)}
              whileFocus={{ scale: 1.05 }}
              transition={{ duration: 0.3 }}
              style={{
                padding: "8px",
                width: "100%",
                marginBottom: "10px",
                height: "60px",
                border: "1px solid #8B4513",
                borderRadius: "5px",
              }}
            ></motion.textarea>
            <br />
            <motion.button
              onClick={submitAdvisory}
              whileHover={{ scale: 1.1 }}
              whileTap={{ scale: 0.9 }}
              style={{
                padding: "10px 20px",
                backgroundColor: "#066b06",
                color: "white",
                border: "none",
                borderRadius: "5px",
                cursor: "pointer",
                fontWeight: "bold",
              }}
            >
              Submit
            </motion.button>
            {loading && <p>Loading...</p>}
            {error && <p style={{ color: "red" }}>{error}</p>}
          </div>

          <h3 style={{ color: "#121111", marginTop: "20px" }}>Recent Advisories</h3>
          {advisories.length === 0 ? (
            <p>No advisories yet.</p>
          ) : (
            <ul style={{ listStyleType: "none", padding: 0 }}>
              <AnimatePresence>
                {(showAll ? advisories : advisories.slice(0, 2)).map((adv, index) => (
                  <motion.li
                    key={adv.id}
                    initial={{ opacity: 0, y: 30, scale: 0.9 }}
                    animate={{ opacity: 1, y: 0, scale: 1 }}
                    exit={{ opacity: 0, y: -10, scale: 0.9 }}
                    transition={{ duration: 0.5, ease: "easeOut", delay: index * 0.1 }}
                    style={{
                      background: "#FFF8DC",
                      margin: "10px 0",
                      padding: "10px",
                      borderRadius: "5px",
                      border: "1px solid #8B4513",
                    }}
                  >
                    <strong style={{ color: "#066b06" }}>{adv.user}</strong>: {adv.advisory}
                  </motion.li>
                ))}
              </AnimatePresence>
            </ul>
          )}

          {advisories.length > 5 && (
            <motion.button
              onClick={() => setShowAll(!showAll)}
              whileHover={{ scale: 1.1 }}
              whileTap={{ scale: 0.9 }}
              style={{
                marginTop: "10px",
                padding: "8px 15px",
                backgroundColor: "#066b06",
                color: "white",
                border: "none",
                borderRadius: "5px",
                cursor: "pointer",
                fontWeight: "bold",
              }}
            >
              {showAll ? "Show Less" : "Show All Advisories"}
            </motion.button>
          )}
        </motion.div>
      </div>
    </div>
  );
};

export default AdvisoryForm;
